import{_ as e,o as i,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const d=JSON.parse('{"title":"精选教程","description":"","frontmatter":{},"headers":[],"relativePath":"resources/tutorials.md","filePath":"resources/tutorials.md","lastUpdated":null}'),t={name:"resources/tutorials.md"};function r(s,a,h,u,n,f){return i(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="精选教程" tabindex="-1">精选教程 <a class="header-anchor" href="#精选教程" aria-label="Permalink to &quot;精选教程&quot;">​</a></h1><p>一句话：优先看官方文档、官方示例和长期维护资料；社区教程只作补充，遇到版本差异以官方为准。</p><h2 id="先看什么" tabindex="-1">先看什么 <a class="header-anchor" href="#先看什么" aria-label="Permalink to &quot;先看什么&quot;">​</a></h2><p>如果刚开始学 AI 绘画，建议按这个顺序看：</p><ol><li>先用 ComfyUI 官方教程跑通文生图。</li><li>再学习 LoRA、ControlNet 和工作流示例。</li><li>最后再看模型卡、许可证和训练资料。</li></ol><p>教程更新很快。阅读时要注意教程发布时间、工具版本、模型版本、节点版本和下载来源。</p><h2 id="comfyui-入门" tabindex="-1">ComfyUI 入门 <a class="header-anchor" href="#comfyui-入门" aria-label="Permalink to &quot;ComfyUI 入门&quot;">​</a></h2><h3 id="comfyui-官方中文文档" tabindex="-1">ComfyUI 官方中文文档 <a class="header-anchor" href="#comfyui-官方中文文档" aria-label="Permalink to &quot;ComfyUI 官方中文文档&quot;">​</a></h3><p>地址：<a href="https://docs.comfy.org/zh" target="_blank" rel="noreferrer">https://docs.comfy.org/zh</a></p><p>用途：</p><ul><li>了解 ComfyUI 的界面、节点和基础概念。</li><li>查找官方维护的中文教程入口。</li><li>遇到社区教程说法不一致时，用官方文档做基准。</li></ul><h3 id="文生图教程" tabindex="-1">文生图教程 <a class="header-anchor" href="#文生图教程" aria-label="Permalink to &quot;文生图教程&quot;">​</a></h3><p>地址：<a href="https://docs.comfy.org/zh/tutorials/basic/text-to-image" target="_blank" rel="noreferrer">https://docs.comfy.org/zh/tutorials/basic/text-to-image</a></p><p>用途：</p><ul><li>跑通最基础的 text-to-image 流程。</li><li>理解 checkpoint、prompt、采样器和输出节点之间的关系。</li><li>适合第一次接触 ComfyUI 的用户。</li></ul><h3 id="工作流模板" tabindex="-1">工作流模板 <a class="header-anchor" href="#工作流模板" aria-label="Permalink to &quot;工作流模板&quot;">​</a></h3><p>地址：<a href="https://docs.comfy.org/zh/interface/features/template" target="_blank" rel="noreferrer">https://docs.comfy.org/zh/interface/features/template</a></p><p>用途：</p><ul><li>学习如何复用模板。</li><li>区分模板、工作流和单个节点设置。</li><li>适合已经能打开 ComfyUI、但还不会管理流程的人。</li></ul><h2 id="comfyui-工作流" tabindex="-1">ComfyUI 工作流 <a class="header-anchor" href="#comfyui-工作流" aria-label="Permalink to &quot;ComfyUI 工作流&quot;">​</a></h2><h3 id="lora-教程" tabindex="-1">LoRA 教程 <a class="header-anchor" href="#lora-教程" aria-label="Permalink to &quot;LoRA 教程&quot;">​</a></h3><p>地址：<a href="https://docs.comfy.org/zh/tutorials/basic/lora" target="_blank" rel="noreferrer">https://docs.comfy.org/zh/tutorials/basic/lora</a></p><p>用途：</p><ul><li>学习在 ComfyUI 中加载 LoRA。</li><li>理解 LoRA 权重和基础模型的关系。</li><li>排查 LoRA 不生效、风格过强或模型不匹配的问题。</li></ul><h3 id="controlnet-教程" tabindex="-1">ControlNet 教程 <a class="header-anchor" href="#controlnet-教程" aria-label="Permalink to &quot;ControlNet 教程&quot;">​</a></h3><p>地址：<a href="https://docs.comfy.org/zh/tutorials/controlnet/controlnet" target="_blank" rel="noreferrer">https://docs.comfy.org/zh/tutorials/controlnet/controlnet</a></p><p>用途：</p><ul><li>学习用参考图控制姿势、结构或边缘。</li><li>理解 ControlNet 不是单纯提示词增强，而是图像条件控制。</li><li>适合开始做可控构图和图生图流程时阅读。</li></ul><h3 id="comfyui-官方示例工作流" tabindex="-1">ComfyUI 官方示例工作流 <a class="header-anchor" href="#comfyui-官方示例工作流" aria-label="Permalink to &quot;ComfyUI 官方示例工作流&quot;">​</a></h3><p>地址：<a href="https://comfyanonymous.github.io/ComfyUI_examples/" target="_blank" rel="noreferrer">https://comfyanonymous.github.io/ComfyUI_examples/</a></p><p>用途：</p><ul><li>查看可直接参考的官方示例流程。</li><li>学习不同任务需要哪些节点组合。</li><li>对照自己的工作流排查节点缺失或连接错误。</li></ul><h2 id="webui-a1111" tabindex="-1">WebUI / A1111 <a class="header-anchor" href="#webui-a1111" aria-label="Permalink to &quot;WebUI / A1111&quot;">​</a></h2><h3 id="automatic1111-官方-wiki" tabindex="-1">AUTOMATIC1111 官方 Wiki <a class="header-anchor" href="#automatic1111-官方-wiki" aria-label="Permalink to &quot;AUTOMATIC1111 官方 Wiki&quot;">​</a></h3><p>地址：<a href="https://github.com/AUTOMATIC1111/stable-diffusion-webui/wiki" target="_blank" rel="noreferrer">https://github.com/AUTOMATIC1111/stable-diffusion-webui/wiki</a></p><p>用途：</p><ul><li>查找 Stable Diffusion WebUI 的官方说明。</li><li>理解 WebUI 的功能入口、扩展和参数。</li><li>适合使用 A1111 而不是 ComfyUI 的用户。</li></ul><h3 id="功能说明" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明" aria-label="Permalink to &quot;功能说明&quot;">​</a></h3><p>地址：<a href="https://github.com/AUTOMATIC1111/stable-diffusion-webui/wiki/Features" target="_blank" rel="noreferrer">https://github.com/AUTOMATIC1111/stable-diffusion-webui/wiki/Features</a></p><p>用途：</p><ul><li>查看 WebUI 主要功能列表。</li><li>对照界面理解 txt2img、img2img、inpaint、extras 等模块。</li><li>学习参数含义时作为索引使用。</li></ul><h2 id="模型与训练" tabindex="-1">模型与训练 <a class="header-anchor" href="#模型与训练" aria-label="Permalink to &quot;模型与训练&quot;">​</a></h2><h3 id="hugging-face-model-cards" tabindex="-1">Hugging Face Model Cards <a class="header-anchor" href="#hugging-face-model-cards" aria-label="Permalink to &quot;Hugging Face Model Cards&quot;">​</a></h3><p>地址：<a href="https://huggingface.co/docs/hub/en/model-cards" target="_blank" rel="noreferrer">https://huggingface.co/docs/hub/en/model-cards</a></p><p>用途：</p><ul><li>学习如何阅读模型卡。</li><li>核对许可证、用途限制、训练数据说明和推荐用法。</li><li>下载模型前先看这一类信息。</li></ul><h3 id="diffusers-lora-训练" tabindex="-1">Diffusers LoRA 训练 <a class="header-anchor" href="#diffusers-lora-训练" aria-label="Permalink to &quot;Diffusers LoRA 训练&quot;">​</a></h3><p>地址：<a href="https://huggingface.co/docs/diffusers/en/training/lora" target="_blank" rel="noreferrer">https://huggingface.co/docs/diffusers/en/training/lora</a></p><p>用途：</p><ul><li>理解 LoRA 训练的官方技术路线。</li><li>了解训练脚本、数据集、显存和参数之间的关系。</li><li>适合有一定 Python 和命令行基础后再看。</li></ul><h3 id="kohya-ss-sd-scripts" tabindex="-1">kohya-ss/sd-scripts <a class="header-anchor" href="#kohya-ss-sd-scripts" aria-label="Permalink to &quot;kohya-ss/sd-scripts&quot;">​</a></h3><p>地址：<a href="https://github.com/kohya-ss/sd-scripts" target="_blank" rel="noreferrer">https://github.com/kohya-ss/sd-scripts</a></p><p>用途：</p><ul><li>查看常见 LoRA 训练脚本和参数说明。</li><li>学习训练前的数据准备、模型选择和输出格式。</li><li>适合进阶用户，不建议在没理解模型卡和许可证前直接照抄训练流程。</li></ul><h2 id="中文补充" tabindex="-1">中文补充 <a class="header-anchor" href="#中文补充" aria-label="Permalink to &quot;中文补充&quot;">​</a></h2><h3 id="comfyui-wiki-中文基础教程" tabindex="-1">ComfyUI Wiki 中文基础教程 <a class="header-anchor" href="#comfyui-wiki-中文基础教程" aria-label="Permalink to &quot;ComfyUI Wiki 中文基础教程&quot;">​</a></h3><p>地址：<a href="https://comfyui-wiki.com/zh/tutorial/basic" target="_blank" rel="noreferrer">https://comfyui-wiki.com/zh/tutorial/basic</a></p><p>用途：</p><ul><li>用中文快速了解 ComfyUI 基础流程。</li><li>作为官方文档之外的补充阅读。</li><li>遇到版本差异时，以 ComfyUI 官方文档和实际节点为准。</li></ul><h2 id="进阶与版本敏感资料" tabindex="-1">进阶与版本敏感资料 <a class="header-anchor" href="#进阶与版本敏感资料" aria-label="Permalink to &quot;进阶与版本敏感资料&quot;">​</a></h2><h3 id="comfyui-flux-1-文生图" tabindex="-1">ComfyUI FLUX.1 文生图 <a class="header-anchor" href="#comfyui-flux-1-文生图" aria-label="Permalink to &quot;ComfyUI FLUX.1 文生图&quot;">​</a></h3><p>地址：<a href="https://docs.comfy.org/zh/tutorials/flux/flux-1-text-to-image" target="_blank" rel="noreferrer">https://docs.comfy.org/zh/tutorials/flux/flux-1-text-to-image</a></p><p>用途：</p><ul><li>学习 FLUX.1 在 ComfyUI 中的基础文生图流程。</li><li>了解新模型对文件、节点和显存的要求。</li><li>适合已经跑通过 SDXL 或基础 ComfyUI 流程后再看。</li></ul><h3 id="comfyui-flux-2-klein-指南" tabindex="-1">ComfyUI FLUX.2 Klein 指南 <a class="header-anchor" href="#comfyui-flux-2-klein-指南" aria-label="Permalink to &quot;ComfyUI FLUX.2 Klein 指南&quot;">​</a></h3><p>地址：<a href="https://docs.comfy.org/zh/tutorials/flux/flux-2-klein" target="_blank" rel="noreferrer">https://docs.comfy.org/zh/tutorials/flux/flux-2-klein</a></p><p>用途：</p><ul><li>了解 FLUX.2 Klein 的 ComfyUI 使用方式。</li><li>对比新模型与传统 Stable Diffusion 工作流的差别。</li><li>这类教程版本变化快，使用前要确认模型文件和节点版本。</li></ul><h2 id="选择教程的原则" tabindex="-1">选择教程的原则 <a class="header-anchor" href="#选择教程的原则" aria-label="Permalink to &quot;选择教程的原则&quot;">​</a></h2><ul><li>优先看官方文档和官方示例。</li><li>优先选择写清楚模型版本、工具版本、节点版本和参数的教程。</li><li>下载模型前先读模型卡和许可证。</li><li>不把未知来源模型、素材或训练数据用于公开或商业项目。</li><li>视频教程可以用来熟悉操作，但具体参数和链接要回到官方资料核对。</li></ul>',70)])])}const m=e(t,[["render",r]]);export{d as __pageData,m as default};
